{
  "family": "Ritter Reaction",
  "candidate": {
    "substrate_smiles": [
      "CC(C)(C)O",
      "CC#N"
    ],
    "product_smiles": [
      "CC(=O)NC(C)(C)C"
    ],
    "optional_reagent_smiles": [
      "O=S(=O)(O)O"
    ],
    "rationale": "This is the classic textbook example of the Ritter reaction, using tert-butanol to generate a stable tert-butyl carbocation in the presence of a strong acid (sulfuric acid). This carbocation is then trapped by acetonitrile, the simplest common nitrile, followed by hydrolysis to form N-tert-butylacetamide. All components are simple, acyclic, and clearly illustrate the core transformation: carbocation formation, nitrile capture, and hydrolysis to an amide.",
    "collision_avoidance_note": "This example uses simple, acyclic, non-aromatic substrates (tert-butanol and acetonitrile) to avoid overlap with other named reactions involving arenes, rearrangements, or complex functional groups. The choice of tert-butanol as the carbocation precursor is specific and avoids generic alcohol dehydration or alkene protonation motifs that could be ambiguous."
  }
}
